  1→import DOMPurify from 'dompurify';
  2→import { marked } from 'marked';
  3→
  4→import { StorageKeys } from '@/core/types/common';
  5→import { isChrome, isFirefox } from '@/core/utils/browser';
  6→import { EXTENSION_VERSION } from '@/core/utils/version';
  7→import { getCurrentLanguage } from '@/utils/i18n';
  8→import type { AppLanguage } from '@/utils/language';
  9→import { TRANSLATIONS, type TranslationKey } from '@/utils/translations';
 10→
 11→/**
 12→ * Dynamically import all markdown changelog files.
 13→ * Keyed by relative path, e.g. './notes/1.2.8.md'
 14→ */
 15→const changelogModules = import.meta.glob('./notes/*.md', {
 16→  query: '?raw',
 17→  import: 'default',
 18→  eager: false,
 19→}) as Record<string, () => Promise<string>>;
 20→
 21→const MARKDOWN_IMAGE_URL_REGEX = /!\[([^\]]*)\]\((https?:\/\/[^\s)]+)\)/g;
 22→
 23→const GITHUB_PROMOTION_PATH_PREFIX =
 24→  '/Nagi-ovo/gemini-voyager/raw/main/docs/public/assets/promotion/';
 25→const RAW_GITHUBUSERCONTENT_PROMOTION_PATH_PREFIX =
 26→  '/Nagi-ovo/gemini-voyager/main/docs/public/assets/promotion/';
 27→
 28→function getPromotionRuntimePath(filename: string): string | null {
 29→  switch (filename) {
 30→    case 'Promo-Banner.png':
 31→      return 'changelog-promo-banner.png';
 32→    case 'Promo-Banner-cn.png':
 33→      return 'changelog-promo-banner-cn.png';
 34→    case 'Promo-Banner-jp.png':
 35→      return 'changelog-promo-banner-jp.png';
 36→    case 'Promo-Banner-KO.png':
 37→      return 'changelog-promo-banner-ko.png';
 38→    default:
 39→      return null;
 40→  }
 41→}
 42→
 43→function getRuntimeUrl(path: string): string | null {
 44→  try {
 45→    const runtime = (
 46→      globalThis as typeof globalThis & {
 47→        browser?: { runtime?: { getURL?: (assetPath: string) => string } };
 48→        chrome?: { runtime?: { getURL?: (assetPath: string) => string } };
 49→      }
 50→    ).browser?.runtime;
 51→    const fallbackRuntime = (
 52→      globalThis as typeof globalThis & {
 53→        chrome?: { runtime?: { getURL?: (assetPath: string) => string } };
 54→      }
 55→    ).chrome?.runtime;
 56→    const getUrl = runtime?.getURL ?? fallbackRuntime?.getURL;
 57→    return typeof getUrl === 'function' ? getUrl(path) : null;
 58→  } catch {
 59→    return null;
 60→  }
 61→}
 62→
 63→function extractPromotionRuntimePath(url: URL): string | null {
 64→  const host = url.hostname.toLowerCase();
 65→  const pathname = url.pathname;
 66→  const isGithubPromotionImage =
 67→    (host === 'github.com' && pathname.startsWith(GITHUB_PROMOTION_PATH_PREFIX)) ||
 68→    (host === 'raw.githubusercontent.com' &&
 69→      pathname.startsWith(RAW_GITHUBUSERCONTENT_PROMOTION_PATH_PREFIX));
 70→  if (!isGithubPromotionImage) return null;
 71→
 72→  const filename = pathname.split('/').pop();
 73→  return filename ? getPromotionRuntimePath(filename) : null;
 74→}
 75→
 76→export function resolveChangelogImageUrl(
 77→  url: string,
 78→  runtimeUrlResolver: (path: string) => string | null = getRuntimeUrl,
 79→): string {
 80→  try {
 81→    const parsed = new URL(url);
 82→    const runtimePath = extractPromotionRuntimePath(parsed);
 83→    if (!runtimePath) return url;
 84→
 85→    const runtimeUrl = runtimeUrlResolver(runtimePath);
 86→    return runtimeUrl ?? url;
 87→  } catch {
 88→    return url;
 89→  }
 90→}
 91→
 92→export function rewriteChangelogImageUrls(
 93→  markdown: string,
 94→  runtimeUrlResolver: (path: string) => string | null = getRuntimeUrl,
 95→  shouldRewrite: boolean = true,
 96→): string {
 97→  if (!shouldRewrite) return markdown;
 98→
 99→  return markdown.replace(MARKDOWN_IMAGE_URL_REGEX, (full, alt, url) => {
100→    const resolvedUrl = resolveChangelogImageUrl(url, runtimeUrlResolver);
101→    if (resolvedUrl === url) return full;
102→    return `![${alt}](${resolvedUrl})`;
103→  });
104→}
105→
106→/**
107→ * Strip optional front matter (--- ... ---) from markdown.
108→ */
109→function stripFrontMatter(raw: string): string {
110→  const match = raw.match(/^---\r?\n[\s\S]*?\r?\n---\r?\n([\s\S]*)$/);
111→  return match ? match[1] : raw;
112→}
113→
114→/**
115→ * Extract the section matching the user's language from a multi-language
116→ * markdown file. Falls back to 'en' if the requested language is missing.
117→ */
118→export function extractLocalizedContent(raw: string, lang: AppLanguage): string {
119→  const body = stripFrontMatter(raw);
120→
121→  // Split by <!-- lang:xx --> markers
122→  const sections = new Map<string, string>();
123→  const parts = body.split(/<!--\s*lang:(\w+)\s*-->/);
124→
125→  // parts[0] is text before the first marker (usually empty)
126→  // parts[1] = lang code, parts[2] = content, parts[3] = lang code, etc.
127→  for (let i = 1; i < parts.length; i += 2) {
128→    const langCode = parts[i];
129→    const content = parts[i + 1]?.trim() ?? '';
130→    if (langCode && content) {
131→      sections.set(langCode, content);
132→    }
133→  }
134→
135→  return sections.get(lang) ?? sections.get('en') ?? '';
136→}
137→
138→/**
139→ * Translate a key using an explicit language, bypassing cachedLanguage.
140→ * This avoids race conditions when initI18n() hasn't finished yet.
141→ */
142→function t(key: TranslationKey, lang: AppLanguage): string {
143→  return TRANSLATIONS[lang][key] ?? TRANSLATIONS.en[key] ?? key;
144→}
145→
146→/**
147→ * Get the docs URL for the current language.
148→ * zh is the root locale (no prefix), others use /{locale}/ prefix.
149→ */
150→function getDocsUrl(lang: AppLanguage): string {
151→  const base = 'https://voyager.nagi.fun';
152→  const path = '/guide/getting-started';
153→  if (lang === 'zh') return `${base}${path}`;
154→  return `${base}/${lang}${path}`;
155→}
