377→/**
378→ * Load and render the changelog modal.
379→ * @param version - Which version's changelog to show (defaults to EXTENSION_VERSION)
380→ * @param skipDismissCheck - Skip the dismissed-version check
381→ */
382→async function showChangelogModal(
383→  version = EXTENSION_VERSION,
384→  skipDismissCheck = false,
385→): Promise<HTMLDivElement | null> {
386→  // 1. Check dismissed version
387→  if (!skipDismissCheck) {
388→    const result = await chrome.storage.local.get(StorageKeys.CHANGELOG_DISMISSED_VERSION);
389→    const dismissedVersion = result[StorageKeys.CHANGELOG_DISMISSED_VERSION] as string | undefined;
390→    if (dismissedVersion === EXTENSION_VERSION) return null;
391→  }
392→
393→  // 2. Try to load the changelog for the target version
394→  const modulePath = `./notes/${version}.md`;
395→  const loader = changelogModules[modulePath];
396→  if (!loader) return null;
397→
398→  const rawMarkdown = await loader();
399→
400→  // 3. Get current language and extract localized content
401→  const lang = await getCurrentLanguage();
402→  const localizedContent = rewriteChangelogImageUrls(
403→    extractLocalizedContent(rawMarkdown, lang),
404→    getRuntimeUrl,
405→    isFirefox(),
406→  );
407→  if (!localizedContent) return null;
408→
409→  // 4. Convert markdown to HTML
410→  const rawHtml = await marked.parse(localizedContent);
411→  const sanitizedHtml = DOMPurify.sanitize(rawHtml, {
412→    ALLOWED_TAGS: [
413→      'h1',
414→      'h2',
415→      'h3',
416→      'h4',
417→      'h5',
418→      'h6',
419→      'p',
420→      'br',
421→      'hr',
422→      'ul',
423→      'ol',
424→      'li',
425→      'strong',
426→      'em',
427→      'code',
428→      'pre',
429→      'a',
430→      'img',
431→      'blockquote',
432→    ],
433→    ALLOWED_ATTR: ['href', 'target', 'rel', 'src', 'alt', 'class'],
434→  });
435→
436→  // 5. Inject modal
437→  const { overlay } = createChangelogModal(sanitizedHtml, lang);
438→  document.body.appendChild(overlay);
439→  return overlay;
440→}
441→
442→/**
443→ * Start the changelog feature.
444→ * Shows a version-based changelog popup when the user upgrades to a new version.
445→ * Returns a cleanup function.
446→ */
447→export async function startChangelog(): Promise<() => void> {
448→  let overlayRef: HTMLDivElement | null = null;
449→
450→  // Debug helper: switch DevTools console context to this extension's content script
451→  // (dropdown next to "top" in the console), then call:
452→  //   __gvChangelog()          — show current version
453→  //   __gvChangelog('1.2.8')   — show specific version
454→  (window as unknown as Record<string, unknown>).__gvChangelog = (version?: string) => {
455→    showChangelogModal(version ?? EXTENSION_VERSION, true);
456→  };
457→
458→  try {
459→    overlayRef = await showChangelogModal();
460→  } catch {
461→    // Silently fail — changelog is non-critical
462→  }
463→
464→  return () => {
465→    if (overlayRef) {
466→      overlayRef.remove();
467→      overlayRef = null;
468→    }
469→  };
470→}
