  1→/**
  2→ * Storage Migration Utility
  3→ * Handles migration from localStorage to chrome.storage for cross-domain data sharing
  4→ */
  5→import { logger } from '@/core/services/LoggerService';
  6→import type { IStorageService } from '@/core/services/StorageService';
  7→import type { StorageKey } from '@/core/types/common';
  8→
  9→export interface MigrationResult {
 10→  success: boolean;
 11→  migratedKeys: string[];
 12→  skippedKeys: string[];
 13→  errors: Array<{ key: string; error: string }>;
 14→}
 15→
 16→/**
 17→ * Migrate data from localStorage to chrome.storage
 18→ *
 19→ * @param keys - Array of localStorage keys to migrate
 20→ * @param targetStorage - Target storage service (e.g., promptStorageService)
 21→ * @param options - Migration options
 22→ * @returns Migration result with details
 23→ *
 24→ * @example
 25→ * ```typescript
 26→ * const result = await migrateFromLocalStorage(
 27→ *   [StorageKeys.PROMPT_ITEMS, StorageKeys.PROMPT_PANEL_LOCKED],
 28→ *   promptStorageService,
 29→ *   { deleteAfterMigration: false }
 30→ * );
 31→ * ```
 32→ */
 33→export async function migrateFromLocalStorage(
 34→  keys: StorageKey[],
 35→  targetStorage: IStorageService,
 36→  options: {
 37→    deleteAfterMigration?: boolean; // Whether to delete from localStorage after successful migration
 38→    skipExisting?: boolean; // Skip keys that already exist in target storage
 39→  } = {},
 40→): Promise<MigrationResult> {
 41→  const migrationLogger = logger.createChild('StorageMigration');
 42→  const result: MigrationResult = {
 43→    success: true,
 44→    migratedKeys: [],
 45→    skippedKeys: [],
 46→    errors: [],
 47→  };
 48→
 49→  const { deleteAfterMigration = false, skipExisting = true } = options;
 50→
 51→  for (const key of keys) {
 52→    try {
 53→      // Check if already exists in target storage
 54→      if (skipExisting) {
 55→        const existingResult = await targetStorage.get(key);
 56→        if (existingResult.success) {
 57→          migrationLogger.info(`Skipping key "${key}" - already exists in target storage`);
 58→          result.skippedKeys.push(key);
 59→          continue;
 60→        }
 61→      }
 62→
 63→      // Read from localStorage
 64→      const localValue = localStorage.getItem(key);
 65→      if (localValue === null) {
 66→        migrationLogger.info(`Skipping key "${key}" - not found in localStorage`);
 67→        result.skippedKeys.push(key);
 68→        continue;
 69→      }
 70→
 71→      // Parse the value
 72→      let parsedValue: unknown;
 73→      try {
 74→        parsedValue = JSON.parse(localValue);
 75→      } catch (parseError) {
 76→        migrationLogger.error(`Failed to parse localStorage value for key "${key}"`, {
 77→          parseError,
 78→        });
 79→        result.errors.push({ key, error: 'Failed to parse JSON' });
 80→        result.success = false;
 81→        continue;
 82→      }
 83→
 84→      // Write to target storage
 85→      const writeResult = await targetStorage.set(key, parsedValue);
 86→      if (!writeResult.success) {
 87→        migrationLogger.error(`Failed to write to target storage for key "${key}"`, {
 88→          error: writeResult.error,
 89→        });
 90→        result.errors.push({
 91→          key,
 92→          error: writeResult.error?.message || 'Failed to write to target storage',
 93→        });
 94→        result.success = false;
 95→        continue;
 96→      }
 97→
 98→      migrationLogger.info(`Successfully migrated key "${key}"`);
 99→      result.migratedKeys.push(key);
100→
101→      // Delete from localStorage if requested
102→      if (deleteAfterMigration) {
103→        try {
104→          localStorage.removeItem(key);
105→          migrationLogger.info(`Deleted key "${key}" from localStorage`);
106→        } catch (deleteError) {
107→          migrationLogger.warn(`Failed to delete key "${key}" from localStorage`, { deleteError });
108→          // Don't mark as failure since migration succeeded
109→        }
110→      }
111→    } catch (error) {
112→      migrationLogger.error(`Unexpected error migrating key "${key}"`, { error });
113→      result.errors.push({
114→        key,
115→        error: error instanceof Error ? error.message : 'Unexpected error',
116→      });
117→      result.success = false;
118→    }
119→  }
120→
121→  // Log summary
122→  migrationLogger.info('Migration completed', {
123→    migratedCount: result.migratedKeys.length,
124→    skippedCount: result.skippedKeys.length,
125→    errorCount: result.errors.length,
126→  });
127→
128→  return result;
129→}
130→
131→/**
132→ * Check if migration has been completed for a specific key
133→ *
134→ * @param key - Storage key to check
135→ * @param targetStorage - Target storage service
136→ * @returns True if data exists in target storage (migration completed)
137→ */
138→export async function isMigrationCompleted(
139→  key: StorageKey,
140→  targetStorage: IStorageService,
141→): Promise<boolean> {
142→  const result = await targetStorage.get(key);
143→  return result.success;
144→}
145→
146→/**
147→ * Get migration status for multiple keys
148→ *
149→ * @param keys - Array of keys to check
150→ * @param targetStorage - Target storage service
151→ * @returns Object mapping keys to migration status
152→ */
153→export async function getMigrationStatus(
154→  keys: StorageKey[],
155→  targetStorage: IStorageService,
156→): Promise<Record<string, boolean>> {
157→  const status: Record<string, boolean> = {};
158→
159→  await Promise.all(
160→    keys.map(async (key) => {
161→      status[key] = await isMigrationCompleted(key, targetStorage);
162→    }),
163→  );
164→
165→  return status;
166→}
